    $stopped += [pscustomobject]@{ ProcessId=$targetId; Name=$procInfo.ProcessName; Status='stopped' }
  } catch {
    $stopped += [pscustomobject]@{ ProcessId=$targetId; Name='unknown'; Status='not active' }
  }
}
$stopped | Format-Table -AutoSize | Tee-Object -FilePath audit-results\v8-stopped-mutating-processes-2.txt
Start-Sleep -Seconds 8
$procs = Get-CimInstance Win32_Process | Where-Object { $_.CommandLine -match 'afrotools|cachebust|inject-internal-links|seo-daily-fix|build:deploy|build-dist|npm|node|git' } | Select-Object ProcessId, ParentProcessId, Name, CommandLine
$procs | Format-List | Out-File -FilePath audit-results\v8-process-lockdown-after-raw.txt -Encoding utf8
$procs | ConvertTo-Json -Depth 3 | Out-File -FilePath audit-results\v8-process-lockdown-after.json -Encoding utf8
$procs | Format-List"
